class Solution:
    def numSubarrayProductLessThanK(self, nums, k):
        n = len(nums)
        count = 0
        for i in range(n):
            prod = 1
            for j in range(i, n):
                prod *= nums[j]
                if prod < k:
                    count += 1
                else:
                    break
        return count

