class Solution:
    def numSubarrayProductLessThanK(self, nums, k):
        if k <= 1:
            return 0
        prod = 1
        left = 0
        count = 0
        for right, v in enumerate(nums):
            prod *= v
            while prod >= k:
                prod //= nums[left]
                left += 1
            count += right - left + 1
        return count

